#define WIDTH 800
#define HEIGHT 600

// Constants
const int WIDTH_IMAGE = 32; // Width of each image tile
const int HEIGHT_IMAGE = 24; // Height of each image tile

SDL_Window* window;
SDL_Renderer* renderer;
SDL_Texture* background;
SDL_Texture* snake;
SDL_Texture* food;

int frame = 0;
int speed = 10;
int score = 0;
int dir_x, dir_y;

void init() {
    // Initialize SDL
    if (SDL_Init(SDL_INIT_VIDEO) < 0) {
        printf("SDL_Init error: %s\n", SDL_GetError());
        return;
    }

    // Create window
    window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, WIDTH, HEIGHT, SDL_WINDOW_SHOWN);
    if (!window) {
        printf("SDL_CreateWindow error: %s\n", SDL_GetError());
        SDL_Quit();
        return;
    }

    // Create renderer
    renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);
    if (!renderer) {
        printf("SDL_CreateRenderer error: %s\n", SDL_GetError());
        SDL_DestroyWindow(window);
        SDL_Quit();
        return;
    }

    // Load background image
    background = IMG_LoadTexture(renderer, (SDL_Texture*)malloc(WIDTH * HEIGHT_IMAGE * sizeof(uint32_t)));
    if (!background) {
        printf("IMG_LoadTexture error: %s\n", IMG_GetError());
        SDL_DestroyTexture(renderer->texture);
        SDL_DestroyWindow(window);
        SDL_Quit();
        return;
    }

    // Load snake and food textures
    snake = IMG_LoadTexture(renderer, (SDL_Texture*)malloc(WIDTH * HEIGHT_IMAGE * sizeof(uint32_t)));
    food = IMG_LoadTexture(renderer, (SDL_Texture*)malloc(WIDTH * HEIGHT_IMAGE * sizeof(uint32_t)));

    // Set initial positions
    int snake_x = WIDTH / 2;
    int snake_y = HEIGHT / 2;
    int food_x = rand() % (WIDTH / WIDTH_IMAGE) * WIDTH_IMAGE;
    int food_y = rand() % (HEIGHT / HEIGHT_IMAGE) * HEIGHT_IMAGE;

    // Initialize direction
    dir_x = 0;
    dir_y = 1;

    // Load initial level
    loadLevel(0);

    // Main loop
    while (true) {
        // Handle events
        SDL_Event e;
        while (SDL_PollEvent(&e)) {
            if (e.type == SDL_QUIT) {
                break;
            }
            if (e.type == SDL_KEYDOWN) {
                switch (e.key.keysym.sym) {
                    case SDLK_w:
                        dir_y = -1;
                        break;
                    case SDLK_s:
                        dir_y = 1;
                        break;
                    case SDLK_a:
                        dir_x = -1;
                        break;
                    case SDLK_d:
                        dir_x = 1;
                        break;
                }
            }
        }

        // Update game state
        frame++;
        if (frame >= speed) {
            frame = 0;
            updateSnake();
            updateFood();
            loadLevel(frame);
        }

        // Clear screen
        SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
        SDL_RenderClear(renderer);

        // Draw background
        SDL_RenderCopy(renderer, background, NULL, NULL);

        // Draw snake
        SDL_RenderCopy(renderer, snake, NULL, &SDL_Rect{snake_x, snake_y, WIDTH_IMAGE, HEIGHT_IMAGE});

        // Draw food
        SDL_RenderCopy(renderer, food, NULL, &SDL_Rect{food_x, food_y, WIDTH_IMAGE, HEIGHT_IMAGE});

        // Update screen
        SDL_RenderPresent(renderer);

        // Cap framerate
        SDL_Delay(16); // 60 FPS with 16ms delay
    }
}

void loadLevel(int level) {
    int x = 0;
    int y = 0;

    while (y < HEIGHT / HEIGHT_IMAGE) {
        int row = y * HEIGHT_IMAGE;
        while (x < WIDTH / WIDTH_IMAGE && row + x * HEIGHT_IMAGE <= level * HEIGHT_IMAGE) {
            memcpy((SDL_Texture*)malloc(WIDTH_IMAGE * sizeof(uint32_t)), ((SDL_Surface*)background)->pixels,
                   (width * sizeof(uint32_t)) + row * WIDTH_IMAGE);
            x++;
        }
        y++;
    }
}

void updateSnake() {
    int x = snake_x + dir_x * WIDTH_IMAGE;
    int y = snake_y + dir_y * HEIGHT_IMAGE;

    // Boundary checking
    if (x < 0 || x >= WIDTH || y < 0 || y >= HEIGHT) {
        return;
    }

    // Snake movement
    if (x != food_x || y != food_y) {
        free(snake);
        snake = IMG_LoadTexture(renderer, (SDL_Texture*)malloc(WIDTH * HEIGHT_IMAGE * sizeof(uint32_t)));
        free(background);
        background = IMG_LoadTexture(renderer, (SDL_Texture*)malloc(WIDTH * HEIGHT_IMAGE * sizeof(uint32_t)));
        loadLevel(frame + 1);
    } else {
        score++;
        free(snake);
        snake = IMG_LoadTexture(renderer, (SDL_Texture*)malloc(WIDTH * HEIGHT_IMAGE * sizeof(uint32_t)));
        free(background);
        background = IMG_LoadTexture(renderer, (SDL_Texture*)malloc(WIDTH * HEIGHT_IMAGE * sizeof(uint32_t)));
        loadLevel(frame + 1);
    }
}

int main() {
    init();
    while (true) {}
    return 0;
}
```

This code initializes a window, loads a simple starting level with random positions for snake and food, updates the game state based on user input and snake direction, and renders the level using images. It maintains a smooth frame rate by using `SDL_Delay` for a delay of 16 milliseconds. Adjustments can be made to optimize performance further.

